-- Seed: copies the six real tours scraped from viaggioindia.com into Supabase.
-- Italian content is verbatim from the source site; EN/DE/FR are translated for
-- title/summary/highlights only — itinerary day-by-day is Italian-only and the
-- frontend pick() helper falls back to Italian for other locales until you
-- translate them in the Table Editor.
--
-- Idempotent — safe to re-run; uses ON CONFLICT (slug) to upsert.
-- Run AFTER 0001_init.sql and 0002_content.sql.

insert into public.tours
  (slug, category, title, summary, duration_days, price_from_inr, hero_image, gallery, destinations, highlights, itinerary, rating, review_count, featured, display_order)
values
  'triangolo-doro-khajuraho-varanasi', 'spiritual',
  '{"it": "Triangolo d''Oro, Khajuraho e Varanasi", "en": "Golden Triangle, Khajuraho & Varanasi", "de": "Goldenes Dreieck, Khajuraho & Varanasi", "fr": "Triangle d''Or, Khajuraho et Varanasi"}'::jsonb,
  '{"it": "Da Delhi al Gange sacro, passando per Agra, Jaipur, Orchha, Khajuraho — il viaggio essenziale del Nord.", "en": "From Delhi to the sacred Ganges via Agra, Jaipur, Orchha, Khajuraho — the essential North India journey.", "de": "Von Delhi zum heiligen Ganges über Agra, Jaipur, Orchha, Khajuraho — die essenzielle Nordindien-Reise.", "fr": "De Delhi au Gange sacré, via Agra, Jaipur, Orchha, Khajuraho — le voyage essentiel du Nord."}'::jsonb,
  10, 65000,
  'https://images.unsplash.com/photo-1561361513-2d000a50f0dc?q=80&w=2000',
  array['https://images.unsplash.com/photo-1564507592333-c60657eea523?q=80&w=1600','https://images.unsplash.com/photo-1599661046289-e31897846e41?q=80&w=1600','https://images.unsplash.com/photo-1551918120-9739cb430c6d?q=80&w=1600'],
  '[{"slug": "delhi", "name": {"en": "Delhi", "it": "Delhi", "de": "Delhi", "fr": "Delhi"}}, {"slug": "jaipur", "name": {"en": "Jaipur", "it": "Jaipur", "de": "Jaipur", "fr": "Jaipur"}}, {"slug": "agra", "name": {"en": "Agra", "it": "Agra", "de": "Agra", "fr": "Agra"}}, {"slug": "orchha", "name": {"en": "Orchha", "it": "Orchha", "de": "Orchha", "fr": "Orchha"}}, {"slug": "khajuraho", "name": {"en": "Khajuraho", "it": "Khajuraho", "de": "Khajuraho", "fr": "Khajuraho"}}, {"slug": "varanasi", "name": {"en": "Varanasi", "it": "Varanasi", "de": "Varanasi", "fr": "Varanasi"}}]'::jsonb,
  '[{"it": "Taj Mahal all''alba", "en": "Taj Mahal at sunrise", "de": "Taj Mahal bei Sonnenaufgang", "fr": "Taj Mahal au lever du soleil"}, {"it": "Forte di Amer in elefante", "en": "Amer Fort by elephant", "de": "Amer Fort auf dem Elefanten", "fr": "Fort d''Amer à dos d''éléphant"}, {"it": "Templi erotici di Khajuraho", "en": "Erotic temples of Khajuraho", "de": "Erotische Tempel von Khajuraho", "fr": "Temples érotiques de Khajuraho"}, {"it": "Aarti serale sul Gange", "en": "Evening Ganga Aarti", "de": "Abendliche Ganga-Aarti", "fr": "Aarti du soir sur le Gange"}]'::jsonb,
  '[{"day": 1, "title": {"it": "Arrivo a Delhi"}, "body": {"it": "All''arrivo a Delhi International Airport, sarete accolti dal nostro agente ad essere accompagnati presso l''hotel selezionato. Giornata di riposo e relax in hotel."}}, {"day": 2, "title": {"it": "Delhi - Jaipur"}, "body": {"it": "Dopo colazione partenza per Jaipur. La distanza di 258 km sarà percorsa in 4 ore e mezza circa. Arrivo a Jaipur e registrazione presso l''hotel prescelto. Inizio del tour della città. Nella bella città rosa costruita dal Maharaja Sawai Singh visiterete la bellissima facciata del Hawa Mahal palace, il Palazzo della città dentro il quale si trova un museo e l''osservatorio astronomico Jantar Mantar. La sera possibilità di passeggiare per le strade e il mercato cittadino, nel quale potrete acquistare molti prodotti artigianali famosi: tappeti, gioielli… Ritorno e pernottamento all''Hotel."}}, {"day": 3, "title": {"it": "Jaipur"}, "body": {"it": "Dopo colazione visita al forte di Amer, a circa 11km da centro cittadino, dove salirete sul dorso di un elefante per entrare nel forte. Dentro il forte si trovano molti palazzi e edifici reali dove potrete trascorrere l''intera giornata. Ritorno e pernottamento all''Hotel."}}, {"day": 4, "title": {"it": "Jaipur - Agra"}, "body": {"it": "Dopo colazione partenza per Agra. Lungo la strada sosta a Fatehpur Sikri, la bellissima città fantasma costruita dall''imperatore Akbar. Ci sono molti monumenti importanti in questa città: una grande moschea - la \"Jama Masiid\", uno splendido palazzo - il \"Panch Mahal, e la grande porta d''ingresso simile ad un arco di trionfo - la \"Buland Darwaza\". Sosta anche al Bharatpur Bird Sanctuary, una famosa riserva naturale dei volatili indiani, dove potrete ammirare migliaia di uccelli. Arrivo ad Agra, registrazione e pausa di riposo nell''hotel. . Dopo la pausa visita al forte della città. L''imperatore mogol Akbar costruì questo maestoso forte successivamente modificato dagli imperatori Jahngir e Shah Jahan. Dentro il forte vi sono grandi palazzi, stanze per udienze pubbliche e private e giardini. Ritorno e pernottamento presso l''hotel."}}, {"day": 5, "title": {"it": "Agra - Orchha"}, "body": {"it": "Sveglia all''alba e visita del Taj Mahal alle 6 del mattino. Vista mozzafiato del Taj Mahal all''alba. Questa ora del giorno è perfetta per scattare splendide foto di questo bellissimo monumento di marmo bianco. Il Taj Mahal, il più bel esempio di architettura islamica in India, fu costruito dall''imperatore Shah Jahan per la sua regina Mumtaz Mahal ed è divenuto il simbolo dell''amore eterno. Ritorno all''hotel per la pausa pranzo e partenza per Orchha nel Madhya Pradesh. Situata a 199 km da Gwalior, questa città è famosa per i suoi numerosi templi e palazzi. Arrivo ad Orchha e registrazione presso l''hotel. Visita della città e dei palazzi Jehangir Mahal, Raj Mahal, Rai Parveen Mahal, e dei templi Chaturbhuj Temple, Ram Rajya Temple e Lakshminarayan Temple. Ritorno e pernottamento nell''hotel prescelto."}}, {"day": 6, "title": {"it": "Orchha - Khajuraho"}, "body": {"it": "Dopo colazione partenza per la località di Khajuraho, famosa per i templi costruiti dai Chandellas. Arrivo a Khajuraho e registrazione presso l''hotel. Visita ai gruppi di templi est ed ovest della zona rinomati per i bassorilievi a sfondo erotico, il più famoso dei quali è il Kendriya Mahadev Temple. . Ritorno e pernottamento nell''hotel."}}, {"day": 7, "title": {"it": "Khajuraho - Varanasi"}, "body": {"it": "Dopo colazione visita ad altri importanti templi della zona e successiva partenza per l''aeroporto per prendere il volo destinazione Varanasi. Arrivo a Varanasi, registrazione presso l''hotel e pausa per recuperare forze. Varanasi è una città con una storia di oltre 2500 anni, conosciuta anche con il nome di Kashi, si pensa che sia stata fondata dal re Kashya nel 1200 a.C. Visita della città: Sarnath Temple, dove il Signore Buddha predicò il suo primo sermone, lo Stupa di Chaukhandi, lo Stupa di Dhamek e il famoso pilastro di 20 metri di Ashoka, fatto erigere dall''imperatore stesso nel 258 a.C. Ritorno e pernottamento presso l''hotel prescelto."}}, {"day": 8, "title": {"it": "Varanasi"}, "body": {"it": "Sveglia la mattina presto per una gita in barca sul Gange, fiume sacro agli indù. Sia in barca che camminando sui gradini potrete comunque vedere i molti pellegrini compiendo rituali, cantando e offrendo doni al fiume sacro. Sentirete il profumo dell''incenso e respirerete l''atmosfera spirituale della città mentre il sole si leva alto nel cielo. Ritorno all''hotel per la pausa pranzo. Nel pomeriggio partenza per l''aeroporto per prendere il volo destinazione Delhi. Arrivo a Delhi, registrazione e pernottamento presso l''hotel prescelto."}}, {"day": 9, "title": {"it": "Delhi"}, "body": {"it": "Dopo colazione visita della città. Ad Old Delhi ammirerete il forte rosso, il Jama Masiid e il Qutab Minar. A Nuova Delhi vedrete la sede del Parlamento, la porta dell''India (India Gate), il Bahai Temple e potrete fare shopping nei numerosi mercati della città."}}, {"day": 10, "title": {"it": "Delhi - Partenza"}, "body": {"it": "Giorno libero nel quale potrete continuare la visita alla città oppure i vostri acquisti prima di partire per l''aeroporto di Delhi per il volo di ritorno. Fine del tour \"Triangolo d''oro, Khaujaraho e Varanasi\". pacchetti di giro dell india Viaggio Ayurvedico in Kerala Durata : 11 Giorni Destinazioni : Delhi, Trivandrim, Kovalam Itinerario Spiagge di Goa Durata : 05 Giorni Destinazioni : Goa altri Pacchetti di tour in India Vacanza India Spiaggia Di India Fauna Selvatica in India Montagne Indiane Tempie Indiane Treno di lusso in India Deserto Indiano Trekking in India Yoga e Meditazione Kamasutra Avventura Indiana Vacanza India Dell Himalaya Viaggi India Destinazioni Famose Dell India Turismo In India Pacchetti Di Giro Dell''India Chi Siamo | Racconti di Viaggio in India | Prenotazioni dei tour | Contattaci Copyright © INDIA KARNI"}}]'::jsonb,
  4.9, 110, true, 10
),
